import java.time.LocalDateTime;

/**
 * Person aggregate root.
 * Business rule: a Person may only be updated when its status is VALID.
 */
public class Person {

    private final PersonId id;
    private String firstName;
    private String lastName;
    private String email;
    private PersonStatus status;
    private final LocalDateTime createdAt;
    private LocalDateTime updatedAt;

    /** Creation constructor — sets status to VALID and timestamps to now. */
    public Person(PersonId id, String firstName, String lastName, String email) {
        this.id = id;
        this.firstName = firstName;
        this.lastName = lastName;
        this.email = email;
        this.status = PersonStatus.VALID;
        this.createdAt = LocalDateTime.now();
        this.updatedAt = this.createdAt;
    }

    /** Reconstitution constructor — used by persistence mapper only. */
    public Person(PersonId id, String firstName, String lastName, String email,
                  PersonStatus status, LocalDateTime createdAt, LocalDateTime updatedAt) {
        this.id = id;
        this.firstName = firstName;
        this.lastName = lastName;
        this.email = email;
        this.status = status;
        this.createdAt = createdAt;
        this.updatedAt = updatedAt;
    }

    public void update(String firstName, String lastName, String email) {
        if (!this.status.isValid()) {
            throw new InvalidPersonStateException(this.id, this.status);
        }
