import com.momcorp.persons.domain.port.out.PersonRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class PersonApplicationService
        implements CreatePersonUseCase, FindPersonUseCase, UpdatePersonUseCase, DeletePersonUseCase {

    private final PersonRepository personRepository;

    public PersonApplicationService(PersonRepository personRepository) {
        this.personRepository = personRepository;
    }

    @Override
    public Person createPerson(CreatePersonUseCase.Command command) {
        var person = new Person(PersonId.generate(), command.firstName(), command.lastName(), command.email());
        return personRepository.save(person);
    }

    @Override
    @Transactional(readOnly = true)
    public Person findById(PersonId id) {
        return personRepository.findById(id);
    }

    @Override
    public Person updatePerson(UpdatePersonUseCase.Command command) {
        var person = personRepository.findById(command.id());
        person.update(command.firstName(), command.lastName(), command.email());
        return personRepository.save(person);
    }

    @Override
    public void deletePerson(PersonId id) {
        var person = personRepository.findById(id);
        person.delete();
        personRepository.save(person);
    }
}

