package com.momcorp.persons.adapter.out.persistence;

import com.momcorp.persons.adapter.out.cache.PersonCacheAdapter;
import com.momcorp.persons.domain.model.Person;
import com.momcorp.persons.domain.model.PersonId;
import com.momcorp.persons.domain.model.PersonNotFoundException;
import com.momcorp.persons.domain.port.out.PersonRepository;
import org.springframework.stereotype.Component;

@Component
public class PersonPersistenceAdapter implements PersonRepository {

    private final SpringDataPersonRepository jpaRepository;
    private final PersonCacheAdapter cacheAdapter;
    private final PersonPersistenceMapper mapper;

    public PersonPersistenceAdapter(SpringDataPersonRepository jpaRepository,
                                    PersonCacheAdapter cacheAdapter,
                                    PersonPersistenceMapper mapper) {
        this.jpaRepository = jpaRepository;
        this.cacheAdapter = cacheAdapter;
        this.mapper = mapper;
    }

    @Override
    public Person save(Person person) {
        var saved = jpaRepository.save(mapper.toJpaEntity(person));
        cacheAdapter.evict(person.getId());
        return mapper.toDomain(saved);
    }

    @Override
    public Person findById(PersonId id) {
        return cacheAdapter.find(id)
                .orElseGet(() -> {
                    var entity = jpaRepository.findById(id.value())
                            .orElseThrow(() -> new PersonNotFoundException(id));
                    var person = mapper.toDomain(entity);
                    cacheAdapter.put(person);
                    return person;
                });
    }

    @Override
    public boolean existsById(PersonId id) {
        return jpaRepository.existsById(id.value());
    }
}

