import org.springframework.boot.test.context.TestConfiguration;
import org.springframework.context.annotation.Bean;
import org.springframework.test.context.DynamicPropertyRegistry;
import org.springframework.test.context.DynamicPropertySource;
import org.testcontainers.containers.PostgreSQLContainer;
import org.testcontainers.junit.jupiter.Container;
import org.testcontainers.junit.jupiter.Testcontainers;

import java.util.Optional;

import static org.assertj.core.api.Assertions.*;
import static org.mockito.Mockito.*;

@DataJpaTest
@Testcontainers
class PersonPersistenceAdapterIT {

    @Container
    static PostgreSQLContainer<?> postgres = new PostgreSQLContainer<>("postgres:16-alpine");

    @DynamicPropertySource
    static void datasourceProperties(DynamicPropertyRegistry registry) {
        registry.add("spring.datasource.url", postgres::getJdbcUrl);
        registry.add("spring.datasource.username", postgres::getUsername);
        registry.add("spring.datasource.password", postgres::getPassword);
    }

    @TestConfiguration
    static class Config {
        @Bean
        PersonCacheAdapter personCacheAdapter() {
            var mock = mock(PersonCacheAdapter.class);
            when(mock.find(any())).thenReturn(Optional.empty());
            return mock;
        }
    }

    @Autowired SpringDataPersonRepository jpaRepository;
    @Autowired PersonPersistenceMapper mapper;
    @Autowired PersonCacheAdapter cacheAdapter;

    @Test
    void should_persistAndRetrievePerson_when_savedSuccessfully() {
        var adapter = new PersonPersistenceAdapter(jpaRepository, cacheAdapter, mapper);
        var person = new Person(PersonId.generate(), "Alice", "Wonder", "alice@example.com");

        var saved = adapter.save(person);
        var found = adapter.findById(saved.getId());

        assertThat(found.getFirstName()).isEqualTo("Alice");
        assertThat(found.getEmail()).isEqualTo("alice@example.com");
    }

    @Test
    void should_throwException_when_personNotFound() {
        var adapter = new PersonPersistenceAdapter(jpaRepository, cacheAdapter, mapper);

        assertThatThrownBy(() -> adapter.findById(PersonId.generate()))
                .isInstanceOf(PersonNotFoundException.class);
    }
}

